def assess_narrative(narrative):
    # Rule 1 conditions
    if "symptoms" in narrative.lower() and ("date" in narrative.lower() or "diagnosis" in narrative.lower()):
        return f"Brief clinical assessment pending further evaluation."

    # Rule 2 conditions (noisy, anecdotal, etc.)
    elif any(word in narrative.lower() for word in ["just", "honestly", "tired", "worried", "confused", "hope"]):
        return "INCONCLUSIVE"

    else:
        return "Requires additional context"

